const express = require('express');
const { sendError } = require('../../lib/errors');
const taskService = require('./service');

const router = express.Router();

router.get('/', (req, res) => {
  const statusFilter = req.query.status;
  let tasks = taskService.getAllTasks();

  if (statusFilter) {
    tasks = tasks.filter(task => task.status === statusFilter);
  }

  res.json({ tasks });
});

router.post('/', (req, res) => {
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'INVALID_TITLE', 'Title is required');
  }

  const task = taskService.createTask(title);
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;

  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }

  const task = taskService.updateTask(taskId, { status });
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }

  res.json({ task });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const projectStore = require('../projects/store');

function getAllTasks() {
  return Object.values(projectStore.tasks);
}

function createTask(title) {
  const taskId = randomUUID();
  const task = { id: taskId, title, status: 'todo' };
  projectStore.tasks[taskId] = task;
  return task;
}

function updateTask(taskId, updates) {
  if (!projectStore.tasks[taskId]) {
    return null;
  }

  Object.assign(projectStore.tasks[taskId], updates);
  return projectStore.tasks[taskId];
}

module.exports = { getAllTasks, createTask, updateTask };
